function renderFilters(organizations,cases){
  state.organizations=organizations||[];state.cases=cases||[];
  if(state.activeOrganization&&!state.organizations.some(function(item){return item.id===state.activeOrganization}))state.activeOrganization='';
  if(!state.activeOrganization&&state.organizations.length===1)state.activeOrganization=state.organizations[0].id;
  var scopedCases=state.activeOrganization?state.cases.filter(function(item){return item.organization_id===state.activeOrganization}):[];
  if(state.activeCase&&!scopedCases.some(function(item){return item.id===state.activeCase}))state.activeCase='';
  $('activeCaseCount').textContent=state.organizations.length+'개 기관 · '+state.cases.length+'개 케이스 가동';
  $('organizationFilter').innerHTML='<option value="">전체 기관</option>'+state.organizations.map(function(item){return '<option value="'+item.id+'">'+esc(item.name)+'</option>'}).join('');
  $('organizationFilter').value=state.activeOrganization;
  $('caseFilter').innerHTML='<option value="">전체 케이스</option>'+scopedCases.map(function(item){return '<option value="'+item.id+'">'+esc(item.name)+'</option>'}).join('');
  $('caseFilter').value=state.activeCase;$('caseFilter').disabled=!state.activeOrganization;
  var organization=state.organizations.find(function(item){return item.id===state.activeOrganization});
  var currentCase=state.cases.find(function(item){return item.id===state.activeCase});
  $('activeFilterLabel').textContent=currentCase?((organization?organization.name+' / ':'')+currentCase.name):(organization?organization.name+' / 전체 케이스':'전체 기관');
  renderNeuralOptions();renderPressOrganizationOptions();
}
