    if(!state.organizations.length){var dashboard=await req('/api/poc/master-press/dashboard?_='+Date.now());renderFilters(dashboard.organizations||[],dashboard.cases||[])}
    if(!state.isAdmin){var adminCheck=await fetch('/api/admin/session',{cache:'no-store',credentials:'same-origin'});state.isAdmin=adminCheck.ok}
    renderPressOrganizationOptions();$('syncPressReleases').hidden=!state.isAdmin;
    var params=new URLSearchParams({limit:'80',_:String(Date.now())});if(state.pressOrganization)params.set('organization_id',state.pressOrganization);
    var data=await req('/api/poc/master-press/press-releases?'+params.toString()),status=data.status||{},releaseCounts=status.releases||{},jobs=status.match_jobs||{};
    renderPressReleases(data.items||[]);
    var ragLabel=!status.supabase_enabled?'Supabase 미설정':status.supabase_status==='ready'?'Supabase RAG 준비':status.supabase_status==='syncing'?'Supabase 자동 동기화 중 ('+Number(status.supabase_pending||0).toLocaleString()+')':'Supabase 스키마 적용 대기';
    $('pressStatus').textContent='보도자료 '+Object.values(releaseCounts).reduce(function(sum,value){return sum+Number(value||0)},0).toLocaleString()+'건 · 연관 '+Number(status.related||0).toLocaleString()+'건 · 매칭 대기 '+Number(jobs.pending||0).toLocaleString()+' · '+ragLabel+(status.last_sync_at?' · 최근 자동 수집 '+fmt(status.last_sync_at):'');
    if(focusId)togglePressRelease(focusId,true)
